#include <bits/stdc++.h>
using namespace std;
int n,d[101];
vector<int> g[101];
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		int a;
		while(cin>>a && a){
			g[i].push_back(a);
			d[a]++;
		}
	}
	queue<int> l,s;
	for(int i=1;i<=n;i++)
		if(d[i]==0)s.push(i);
	while(!s.empty()){
		l.push(s.front());
		s.pop();
		for(int i=0;i<g[l.back()].size();i++)
			if(!--d[g[l.back()][i]])s.push(g[l.back()][i]);
	}
	if(l.size()<n)cout<<"orz";
	else{
		while(!l.empty()){
			cout<<l.front()<<' ';
			l.pop();
		}
	}
	return 0;
}
